"use client";

import { 
  LayoutDashboard, 
  Info, 
  Map as MapIcon, 
  Zap, 
  History, 
  FileText,
  Settings,
  HelpCircle,
  BookOpen
} from "lucide-react";
import { cn } from "@/lib/utils";
import Link from "next/link";
import { usePathname } from "next/navigation";

const menuItems = [
  { icon: Info, label: "INFORMATION HUB", href: "/info" },
  { icon: LayoutDashboard, label: "DASHBOARD", href: "/" },
  { icon: MapIcon, label: "INTERACTIVE MAP", href: "/map" },
  { icon: Zap, label: "AGENT LOGIC", href: "/logic" },
  { icon: History, label: "ACTION LOGS", href: "/logs" },
  { icon: FileText, label: "HISTORY", href: "/history" },
];

export default function Sidebar() {
  const pathname = usePathname();

  return (
    <aside className="w-64 bg-white border-r border-slate-200 flex flex-col h-screen sticky top-0 shrink-0">
      {/* LOGO SECTION */}
      <div className="p-6 flex items-center gap-3">
        <div className="w-10 h-10 bg-[#0F172A] rounded-lg flex items-center justify-center">
            {/* Simple Wave Icon for Mekong */}
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" className="text-white">
                <path d="M2 12C2 12 5 7 12 7C19 7 22 12 22 12C22 12 19 17 12 17C5 17 2 12 2 12Z" stroke="currentColor" strokeWidth="2"/>
                <circle cx="12" cy="12" r="3" stroke="currentColor" strokeWidth="2"/>
            </svg>
        </div>
        <div>
          <h1 className="font-bold text-slate-900 leading-tight">Mekong-SALT</h1>
          <p className="text-[10px] text-slate-500 font-medium">AI Salinity Management</p>
        </div>
      </div>

      {/* NAVIGATION */}
      <nav className="flex-1 px-4 py-2 space-y-1">
        {menuItems.map((item) => {
          const isActive = pathname === item.href;
          return (
            <Link
              key={item.label}
              href={item.href}
              className={cn(
                "flex items-center gap-3 px-3 py-3 rounded-xl text-[11px] font-bold tracking-wider transition-all",
                isActive 
                  ? "bg-cyan-50 text-cyan-600 shadow-sm border border-cyan-100" 
                  : "text-slate-500 hover:bg-slate-50 hover:text-slate-900"
              )}
            >
              <item.icon className={cn("w-5 h-5", isActive ? "text-cyan-600" : "text-slate-400")} />
              {item.label}
            </Link>
          );
        })}
      </nav>

      {/* SYSTEM STATUS & FOOTER */}
      <div className="p-4 mt-auto space-y-4">
        <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
          <div className="flex items-center gap-2 mb-1">
            <span className="relative flex h-2 w-2">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
            </span>
            <span className="text-[10px] font-bold text-slate-700 uppercase tracking-tight">System Status: Active</span>
          </div>
          <p className="text-[10px] text-slate-400 font-medium ml-4">Sentinel nodes responding</p>
        </div>

        <div className="space-y-1 px-2">
          <button className="flex items-center gap-2 text-[11px] font-bold text-slate-500 hover:text-slate-900 w-full py-2 transition-colors">
            <HelpCircle className="w-4 h-4" /> Support
          </button>
          <button className="flex items-center gap-2 text-[11px] font-bold text-slate-500 hover:text-slate-900 w-full py-2 transition-colors">
            <BookOpen className="w-4 h-4" /> Documentation
          </button>
        </div>
      </div>
    </aside>
  );
}